/**
 * PF.02 - Normalize positions (1 item = 1 row)
 * - Parses portfolio row values robustly (FR number support)
 * - Excludes technical rows (__META__, CASH_EUR)
 * - Adds config from PF.00 node to each output item
 */

function safeJsonParse(v, fallback = {}) {
  try {
    if (!v) return fallback;
    if (typeof v === "object") return v;
    return JSON.parse(String(v));
  } catch {
    return fallback;
  }
}

function normSymbol(v) {
  return String(v ?? "").trim();
}

function stripSpaces(s) {
  return String(s ?? "").replace(/[\s\u00A0\u202F]/g, "");
}

function parseFrNumber(v) {
  if (v === null || v === undefined || v === "") return null;
  if (typeof v === "number") return Number.isFinite(v) ? v : null;

  const s0 = stripSpaces(v)
    .replace(/EUR/gi, "")
    .replace(/€/g, "")
    .trim();

  if (!s0) return null;

  const s1 = s0.replace(/\./g, "").replace(",", ".");
  const n = Number(s1);
  return Number.isFinite(n) ? n : null;
}

function getRowNum(r) {
  const n = Number(r?.row_number);
  return Number.isFinite(n) ? n : null;
}

function normDbPath(v) {
  return String(v ?? "").trim();
}

function loadConfig() {
  const candidates = ["PF.00 - Config", "PF.00", "Config"];
  for (const name of candidates) {
    try {
      const it = $items(name);
      if (it?.length) return it[0].json ?? {};
    } catch {}
  }
  return {};
}

const cfg = loadConfig();
const rows = $input.all().map(i => i.json || {});

// Group rows by portfolio DB path so each portfolio keeps its own cash/meta context.
const groups = new Map();
for (const r of rows) {
  const dbPath = normDbPath(r.portfolio_db_path || r.db_path || cfg.portfolio_db_path);
  const key = dbPath || "__NO_DB__";
  if (!groups.has(key)) groups.set(key, []);
  groups.get(key).push(r);
}

const out = [];

for (const [dbPath, grpRows] of groups.entries()) {
  const metaRow = grpRows.find(r => normSymbol(r.Symbol) === "__META__") || null;
  const cashRow = grpRows.find(r => normSymbol(r.Symbol) === "CASH_EUR") || null;

  const metaRowNumSrc = getRowNum(metaRow);
  const cashRowNumSrc = getRowNum(cashRow);

  const headerOffset = (metaRowNumSrc === 1) ? 1 : 0;
  const metaRowNumber = (metaRowNumSrc ?? 1) + headerOffset;
  const cashRowNumber = (cashRowNumSrc ?? 2) + headerOffset;

  const initialCapitalEUR = metaRow ? parseFrNumber(metaRow.MarketValue) : 50000;
  const cashMarketValueRaw = cashRow?.MarketValue ?? cashRow?.LastPrice ?? "";
  const cashMarketValueEUR = parseFrNumber(cashMarketValueRaw);

  const pf_ctx = {
    portfolio_db_path: dbPath === "__NO_DB__" ? "" : dbPath,
    headerOffset,
    meta: {
      row_number: metaRowNumber,
      row_number_src: metaRowNumSrc,
      UpdatedAt: metaRow?.UpdatedAt ?? null,
      initialCapitalEUR,
    },
    cash: {
      row_number: cashRowNumber,
      row_number_src: cashRowNumSrc,
      UpdatedAt: cashRow?.UpdatedAt ?? null,
      MarketValueRaw: cashMarketValueRaw,
      MarketValueEUR: cashMarketValueEUR,
    },
  };

  const positions = grpRows.filter(r => {
    const sym = normSymbol(r.Symbol);
    if (!sym) return false;
    if (sym === "__META__") return false;
    if (sym === "CASH_EUR") return false;

    const q = r.Quantity ?? r.qty;
    return q !== null && q !== undefined && String(q).trim() !== "";
  });

  for (const r of positions) {
    const rowNumSrc = getRowNum(r);
    const rowNumSheet = rowNumSrc !== null ? (rowNumSrc + headerOffset) : null;

    const symbol = normSymbol(r.Symbol);
    const qty = parseFrNumber(r.Quantity ?? r.qty);
    const avgPrice = parseFrNumber(r.AvgPrice ?? r.avgPrice);

    out.push({
      ...cfg,
      ...r,
      portfolio_db_path: dbPath === "__NO_DB__" ? (r.portfolio_db_path || cfg.portfolio_db_path || "") : dbPath,
      pf_ctx,
      row_number_src: rowNumSrc,
      row_number: rowNumSheet ?? rowNumSrc,
      symbol,
      qty,
      avgPrice,
      Name: r.Name,
      AssetClass: r.AssetClass,
      Sector: r.Sector,
      Industry: r.Industry,
      ISIN: r.ISIN,
    });
  }
}

return out.map(j => ({ json: j }));

// PF.05A - Wrap 1D response
return $input.all().map((it) => {
  const r = it.json ?? {};
  return { json: { symbol: r.symbol, yf_1d: r } };
});

// PF.05B - Wrap 1H response
return $input.all().map((it) => {
  const r = it.json ?? {};
  return { json: { symbol: r.symbol, yf_1h: r } };
});

// PF.07 - Compute MTM (skip-safe)
// Input: enriched portfolio item (row_number, qty/avgPrice, yf_1d, optional yf_1h)
// Output: same fields + LastPrice / MarketValue / UnrealizedPnL + diagnostics + gs_update

function safeNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function parseTime(t) {
  const d = new Date(t);
  const ms = d.getTime();
  return Number.isFinite(ms) ? ms : null;
}

function extractLast(yf) {
  if (!yf || typeof yf !== "object") return null;
  if (yf.ok === false) return { ok: false, reason: yf.error || "YF_OK_FALSE" };

  if (yf.last && typeof yf.last === "object") {
    const price = safeNum(yf.last.c);
    const tMs = parseTime(yf.last.t);
    if (price != null) {
      return {
        ok: true,
        price,
        t: yf.last.t || null,
        tMs,
        interval: yf.interval || null,
        source: yf.source || null,
        stale: !!yf.stale,
      };
    }
  }

  if (Array.isArray(yf.bars) && yf.bars.length) {
    const b = yf.bars[yf.bars.length - 1];
    const price = safeNum(b?.c);
    const tMs = parseTime(b?.t);
    if (price != null) {
      return {
        ok: true,
        price,
        t: b.t || null,
        tMs,
        interval: yf.interval || null,
        source: yf.source || null,
        stale: !!yf.stale,
      };
    }
  }

  return { ok: false, reason: "NO_LAST_PRICE_IN_PAYLOAD" };
}

return $input.all().map((it) => {
  const j = it.json ?? {};

  const qty = safeNum(j.qty ?? j.Quantity);
  const avgPrice = safeNum(j.avgPrice ?? j.AvgPrice);

  const last1d = extractLast(j.yf_1d);
  const last1h = extractLast(j.yf_1h);

  let chosen = null;
  if (last1h?.ok && last1d?.ok) {
    if (last1h.tMs != null && last1d.tMs != null) {
      chosen = (last1h.tMs >= last1d.tMs) ? { ...last1h, picked: "1h" } : { ...last1d, picked: "1d" };
    } else {
      chosen = { ...last1h, picked: "1h" };
    }
  } else if (last1h?.ok) {
    chosen = { ...last1h, picked: "1h" };
  } else if (last1d?.ok) {
    chosen = { ...last1d, picked: "1d" };
  }

  const fallbackLastPrice = safeNum(j.LastPrice);
  if (!chosen && fallbackLastPrice != null && fallbackLastPrice > 0) {
    chosen = {
      ok: true,
      price: fallbackLastPrice,
      t: j.asof || j.UpdatedAt || null,
      tMs: parseTime(j.asof || j.UpdatedAt),
      interval: "fallback",
      source: "portfolio_input",
      stale: true,
      picked: "fallback",
    };
  }

  const updatedAt = new Date().toISOString();

  let mtm_ok = true;
  let mtm_status = "OK";
  let mtm_reason = null;

  const price = chosen?.ok ? chosen.price : null;

  if (qty == null || avgPrice == null) {
    mtm_ok = false;
    mtm_status = "INVALID_INPUT";
    mtm_reason = "Missing qty or avgPrice";
  } else if (price == null) {
    mtm_ok = false;
    mtm_status = "NO_PRICE";
    mtm_reason = `No usable price from yf_1h/yf_1d (1h=${last1h?.reason || "n/a"}, 1d=${last1d?.reason || "n/a"})`;
  }

  const MarketValue = (mtm_ok ? qty * price : safeNum(j.MarketValue) ?? 0);
  const UnrealizedPnL = (mtm_ok ? qty * (price - avgPrice) : safeNum(j.UnrealizedPnL) ?? 0);

  const out = {
    ...j,

    LastPrice: mtm_ok ? price : (safeNum(j.LastPrice) ?? 0),
    MarketValue,
    UnrealizedPnL,
    UpdatedAt: updatedAt,

    mtm_ok,
    mtm_status,
    mtm_reason,
    mtm_price: price,
    mtm_price_picked: chosen?.picked || null,
    mtm_price_asof: chosen?.t || null,
    mtm_price_interval: chosen?.interval || null,
    mtm_price_source: chosen?.source || null,
    mtm_price_stale: chosen?.stale ?? null,

    gs_update: {
      row_number: j.row_number,
      LastPrice: mtm_ok ? price : (safeNum(j.LastPrice) ?? 0),
      MarketValue,
      UnrealizedPnL,
      UpdatedAt: updatedAt,
    },
  };

  if (out.yf_1d?.bars) delete out.yf_1d.bars;
  if (out.yf_1h?.bars) delete out.yf_1h.bars;

  return { json: out };
});

// PF.08 - Build DuckDB payloads
// Input: items from PF.07 (1 item = 1 position with MTM)
// Output: per-portfolio rows for PF.08B (DuckDB writer), plus placeholders when a portfolio has 0 positions

function safeNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

function safeNumOrNull(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function round2(v) {
  const n = safeNum(v);
  return Math.round((n + Number.EPSILON) * 100) / 100;
}

function makeFallbackRunId() {
  const d = new Date();
  const pad = (x) => String(x).padStart(2, "0");
  return `PFMTM_${d.getUTCFullYear()}${pad(d.getUTCMonth() + 1)}${pad(d.getUTCDate())}${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}`;
}

function safeJsonParse(v, fallback = null) {
  try {
    if (v == null || v === "") return fallback;
    if (typeof v === "object") return v;
    return JSON.parse(String(v));
  } catch {
    try {
      const s = String(v ?? "");
      if (s.includes(";")) {
        return JSON.parse(s.replace(/;/g, ","));
      }
    } catch {}
    return fallback;
  }
}

function normPath(v) {
  const s = String(v ?? "").trim();
  return s || null;
}

function isLegacyAg1DbPath(v) {
  const s = String(v ?? "").trim().toLowerCase().replace(/\\/g, "/");
  return s.endsWith("/ag1_v2.duckdb");
}

function normSymbol(v) {
  return String(v ?? "").trim().toUpperCase();
}

function uniqPaths(arr) {
  const out = [];
  const seen = new Set();
  for (const x of arr || []) {
    const p = normPath(x);
    if (!p) continue;
    const k = p.toLowerCase();
    if (seen.has(k)) continue;
    seen.add(k);
    out.push(p);
  }
  return out;
}

function getRowNum(r) {
  const n = Number(r?.row_number);
  return Number.isFinite(n) ? n : null;
}

function stripSpaces(s) {
  return String(s ?? "").replace(/[\s\u00A0\u202F]/g, "");
}

function parseFrNumber(v) {
  if (v === null || v === undefined || v === "") return null;
  if (typeof v === "number") return Number.isFinite(v) ? v : null;
  const s0 = stripSpaces(v).replace(/EUR/gi, "").replace(/â‚¬/g, "").trim();
  if (!s0) return null;
  const s1 = s0.replace(/\./g, "").replace(",", ".");
  const n = Number(s1);
  return Number.isFinite(n) ? n : null;
}

function safeNodeItems(nodeName) {
  try {
    return $items(nodeName).map((i) => i.json || {});
  } catch {
    return [];
  }
}

function loadConfig() {
  const candidates = ["PF.00 - Config", "PF.00", "Config"];
  for (const name of candidates) {
    const arr = safeNodeItems(name);
    if (arr.length) return arr[0] || {};
  }
  return {};
}

function resolvePortfolioDbPaths(cfg, inItems, readRows) {
  const arr1 = Array.isArray(cfg?.portfolio_db_paths) ? cfg.portfolio_db_paths : [];
  const parsedJson = safeJsonParse(cfg?.portfolio_db_paths_json, null);
  const arr2 = Array.isArray(parsedJson) ? parsedJson : [];
  const csv = String(cfg?.portfolio_db_paths_csv ?? "").trim();
  const arr3 = csv ? csv.split(/[;,]/).map((x) => x.trim()) : [];
  const singles = [
    cfg?.portfolio_db_path,
    ...inItems.map((j) => j?.portfolio_db_path || j?.db_path),
    ...readRows.map((r) => r?.portfolio_db_path || r?.db_path),
  ];
  const fallback = ["/local-files/duckdb/ag1_v2_chatgpt52.duckdb"];
  return uniqPaths([...arr1, ...arr2, ...arr3, ...singles, ...fallback]).filter((p) => !isLegacyAg1DbPath(p));
}

function buildPfCtxFromRows(rows, dbPath) {
  const metaRow = rows.find((r) => normSymbol(r.Symbol) === "__META__") || null;
  const cashRow = rows.find((r) => normSymbol(r.Symbol) === "CASH_EUR") || null;

  const metaRowNumSrc = getRowNum(metaRow);
  const cashRowNumSrc = getRowNum(cashRow);
  const headerOffset = (metaRowNumSrc === 1) ? 1 : 0;

  const initialCapitalEUR = metaRow ? parseFrNumber(metaRow.MarketValue) : null;
  const cashMarketValueRaw = cashRow?.MarketValue ?? cashRow?.LastPrice ?? "";
  const cashMarketValueEUR = parseFrNumber(cashMarketValueRaw);

  return {
    portfolio_db_path: dbPath || "",
    headerOffset,
    meta: {
      row_number: (metaRowNumSrc ?? 1) + headerOffset,
      row_number_src: metaRowNumSrc,
      UpdatedAt: metaRow?.UpdatedAt ?? null,
      initialCapitalEUR,
    },
    cash: {
      row_number: (cashRowNumSrc ?? 2) + headerOffset,
      row_number_src: cashRowNumSrc,
      UpdatedAt: cashRow?.UpdatedAt ?? null,
      MarketValueRaw: cashMarketValueRaw,
      MarketValueEUR: cashMarketValueEUR,
    },
  };
}

const nowIso = new Date().toISOString();
const inItems = $input.all().map((i) => i.json || {});
const cfg = loadConfig();
const readRows = safeNodeItems("Read Portfolio");
const fallbackRunId = makeFallbackRunId();
const sharedRunId =
  String(inItems.find((j) => j?.run_id)?.run_id || cfg.run_id || fallbackRunId);

// Build/collect per-portfolio context (cash/meta rows) from the raw portfolio reader first.
const readRowsByDb = new Map();
for (const r of readRows) {
  const dbPath = normPath(r.portfolio_db_path || r.db_path || cfg.portfolio_db_path);
  if (!dbPath) continue;
  if (!readRowsByDb.has(dbPath)) readRowsByDb.set(dbPath, []);
  readRowsByDb.get(dbPath).push(r);
}

const ctxByDb = new Map();
for (const [dbPath, rows] of readRowsByDb.entries()) {
  ctxByDb.set(dbPath, buildPfCtxFromRows(rows, dbPath));
}

for (const j of inItems) {
  const dbPath = normPath(j.portfolio_db_path || j.db_path || cfg.portfolio_db_path);
  if (!dbPath) continue;
  if (j?.pf_ctx && !ctxByDb.has(dbPath)) {
    ctxByDb.set(dbPath, j.pf_ctx);
  }
}

const targetDbPaths = resolvePortfolioDbPaths(cfg, inItems, readRows);
const seenPositionDbs = new Set();

const positionUpdates = inItems
  .filter((j) => j?.gs_update?.row_number != null)
  .map((j) => {
    const u = j.gs_update;
    let primaryDbPath = normPath(j.portfolio_db_path || j.db_path || cfg.portfolio_db_path);
    if (!primaryDbPath || isLegacyAg1DbPath(primaryDbPath)) {
      primaryDbPath = "/local-files/duckdb/ag1_v2_chatgpt52.duckdb";
    }
    seenPositionDbs.add(primaryDbPath);
    const pfCtx = j.pf_ctx || ctxByDb.get(primaryDbPath) || {};
    const pfCash = pfCtx.cash || {};
    const pfMeta = pfCtx.meta || {};
    return {
      row_number: u.row_number,
      LastPrice: round2(u.LastPrice),
      MarketValue: round2(u.MarketValue),
      UnrealizedPnL: round2(u.UnrealizedPnL),
      UpdatedAt: u.UpdatedAt || nowIso,

      Name: j.Name ?? "",
      AssetClass: j.AssetClass ?? "",
      Sector: j.Sector ?? "",
      Industry: j.Industry ?? "",

      // Extra fields for DuckDB persistence node
      Symbol: j.symbol || j.Symbol || "",
      ISIN: j.ISIN || "",
      Quantity: j.qty ?? j.Quantity ?? "",
      AvgPrice: j.avgPrice ?? j.AvgPrice ?? "",
      run_id: j.run_id || sharedRunId,
      portfolio_db_path: primaryDbPath,
      workflow_name: j.workflow_name || cfg.workflow_name || "PF Portfolio MTM Updater (DuckDB-only, Multi AG1-V2)",

      mtm_ok: j.mtm_ok,
      mtm_status: j.mtm_status,
      mtm_reason: j.mtm_reason,
      mtm_price_picked: j.mtm_price_picked,
      mtm_price_asof: j.mtm_price_asof,

      // Portfolio context persisted by PF.08B in DuckDB technical rows (per portfolio).
      pf_cash_market_value: safeNum(pfCash.MarketValueEUR),
      pf_cash_updated_at: pfCash.UpdatedAt || nowIso,
      pf_initial_capital: safeNumOrNull(pfMeta.initialCapitalEUR),
      pf_meta_updated_at: pfMeta.UpdatedAt || nowIso,
    };
  });

// Ensure PF.08B can still persist CASH_EUR/__META__ for portfolios with zero equity rows.
for (const dbPath of targetDbPaths) {
  if (seenPositionDbs.has(dbPath)) continue;
  const pfCtx = ctxByDb.get(dbPath) || {};
  const pfCash = pfCtx.cash || {};
  const pfMeta = pfCtx.meta || {};
  positionUpdates.push({
    row_number: null,
    LastPrice: 0,
    MarketValue: 0,
    UnrealizedPnL: 0,
    UpdatedAt: nowIso,
    Name: "",
    AssetClass: "",
    Sector: "",
    Industry: "",
    Symbol: "",
    ISIN: "",
    Quantity: "",
    AvgPrice: "",
    run_id: sharedRunId,
    portfolio_db_path: dbPath,
    workflow_name: cfg.workflow_name || "PF Portfolio MTM Updater (DuckDB-only, Multi AG1-V2)",
    mtm_ok: true,
    mtm_status: "NO_POSITION_ROWS",
    mtm_reason: "",
    mtm_price_picked: null,
    mtm_price_asof: null,
    pf_cash_market_value: safeNum(pfCash.MarketValueEUR),
    pf_cash_updated_at: pfCash.UpdatedAt || nowIso,
    pf_initial_capital: safeNumOrNull(pfMeta.initialCapitalEUR),
    pf_meta_updated_at: pfMeta.UpdatedAt || nowIso,
  });
}

// Safety net if no targets were resolved but PF.08 still executes.
if (positionUpdates.length === 0) {
  let primaryDbPath = normPath(cfg.portfolio_db_path);
  if (!primaryDbPath || isLegacyAg1DbPath(primaryDbPath)) {
    primaryDbPath = "/local-files/duckdb/ag1_v2_chatgpt52.duckdb";
  }
  positionUpdates.push({
    row_number: null,
    LastPrice: 0,
    MarketValue: 0,
    UnrealizedPnL: 0,
    UpdatedAt: nowIso,
    Name: "",
    AssetClass: "",
    Sector: "",
    Industry: "",
    Symbol: "",
    ISIN: "",
    Quantity: "",
    AvgPrice: "",
    run_id: sharedRunId,
    portfolio_db_path: primaryDbPath,
    workflow_name: cfg.workflow_name || "PF Portfolio MTM Updater (DuckDB-only, Multi AG1-V2)",
    mtm_ok: true,
    mtm_status: "NO_POSITION_ROWS",
    mtm_reason: "NO_TARGET_PORTFOLIO_ROWS_FOUND",
    mtm_price_picked: null,
    mtm_price_asof: null,
    pf_cash_market_value: 0,
    pf_cash_updated_at: nowIso,
    pf_initial_capital: null,
    pf_meta_updated_at: nowIso,
  });
}

return positionUpdates.map((o) => ({ json: o }));
